function generateHeatmapDataD3(
  tasks: TaskRender[],
  totalDays: number,
  trainCount: number,
  gridCols: number,
  gridRows: number
): number[][] {
  const daysPerCell = totalDays / gridCols;
  const trainsPerCell = trainCount / gridRows;

  // Create time bins
  const timeBins = bin()
    .domain([0, totalDays])
    .thresholds(gridCols)
    (tasks.map(t => t.startDay));

  // Create train bins
  const trainBins = bin()
    .domain([0, trainCount])
    .thresholds(gridRows)
    (tasks.map(t => t.trainIndex));

  // 2D rollup: count tasks per (trainBin, timeBin)
  const aggregated = rollup(
    tasks,
    v => v.length,  // Count
    t => Math.floor(t.trainIndex / trainsPerCell),
    t => Math.floor(t.startDay / daysPerCell)
  );

  // Convert to grid
  const grid = Array(gridRows).fill(null).map(() => Array(gridCols).fill(0));
  aggregated.forEach((rowMap, row) => {
    rowMap.forEach((count, col) => {
      grid[row][col] = count;
    });
  });

  return grid;
}
